/**
 * window.electronAPI 类型声明
 * 与 src/preload/index.ts 的 ElectronAPI 类型保持同步
 */

export interface ElectronAPI {
  // 对话框
  openDirectory: () => Promise<string | undefined>

  // 文件系统 - 读取操作
  readFile: (filePath: string) => Promise<{ success: boolean; content?: string; error?: string }>
  exists: (filePath: string) => Promise<boolean>
  readdir: (dirPath: string) => Promise<Array<{ name: string; isDirectory: boolean; isFile: boolean }>>

  // 文件系统 - 写入操作
  writeFile: (filePath: string, content: string) => Promise<{ success: boolean; error?: string }>
  mkdir: (dirPath: string) => Promise<{ success: boolean; error?: string }>

  // 文件系统 - 删除操作
  unlink: (filePath: string) => Promise<{ success: boolean; error?: string }>
  rmdir: (dirPath: string, options?: { recursive?: boolean }) => Promise<{ success: boolean; error?: string }>
  remove: (targetPath: string) => Promise<{ success: boolean; error?: string }>
  deleteFile: (filePath: string) => Promise<{ success: boolean; error?: string }>
  deleteDirectory: (dirPath: string) => Promise<{ success: boolean; error?: string }>
  renameFile: (oldPath: string, newPath: string) => Promise<{ success: boolean; error?: string }>

  // 系统
  openPath: (path: string) => Promise<string>
  getProjectRoot: () => Promise<string | null>

  // 文件监听
  fsWatch: (dirPath?: string) => Promise<{ success: boolean; path?: string; error?: string }>
  fsUnwatch: () => Promise<{ success: boolean; error?: string }>
  onFsChange: (callback: (data: { type: string; fileName: string; path: string }) => void) => () => void

  // 安全存储
  safeStorage: {
    encrypt: (plainText: string) => Promise<{ success: boolean; data?: Buffer; error?: string }>
    decrypt: (encrypted: Buffer) => Promise<{ success: boolean; data?: string; error?: string }>
    isAvailable: () => Promise<{ success: boolean; available?: boolean; error?: string }>
  }

  // YAML 服务
  yaml: {
    read: (filePath: string) => Promise<{ success: boolean; data?: unknown; error?: string }>
    write: (filePath: string, data: unknown) => Promise<{ success: boolean; error?: string }>
  }

  // AI 服务
  ai: {
    saveApiKey: (service: string, apiKey: string) => Promise<{ success: boolean; error?: string }>
    isConfigured: (service: string) => Promise<{ success: boolean; configured?: boolean; error?: string }>
    getConfiguredServices: () => Promise<{ success: boolean; services?: string[]; error?: string }>
    call: (prompt: string, options?: Record<string, unknown>) => Promise<{ success: boolean; content?: string; error?: string }>
    stream: (prompt: string, options?: Record<string, unknown>) => Promise<{ success: boolean; error?: string }>
    onStreamChunk: (callback: (chunk: { content: string; done: boolean; reasoning?: string }) => void) => () => void
    onStreamError: (callback: (error: string) => void) => () => void
    testConnection: (service: string) => Promise<{ success: boolean; result?: boolean; error?: string }>
    saveSetting: (key: string, value: unknown) => Promise<{ success: boolean; error?: string }>
    getSetting: (key: string, defaultValue?: unknown) => Promise<{ success: boolean; value?: unknown; error?: string }>
  }

  // 备份服务
  backup: {
    create: () => Promise<{ success: boolean; backupPath?: string; error?: string }>
    list: () => Promise<{ success: boolean; backups?: Array<{ name: string; path: string; date: string; size: number }>; error?: string }>
    restore: (backupPath: string, targetPath?: string) => Promise<{ success: boolean; error?: string }>
    delete: (backupPath: string) => Promise<{ success: boolean; error?: string }>
  }
}

declare global {
  interface Window {
    electronAPI: ElectronAPI
  }
}

/**
 * 番茄小说创作助手 - Electron 主进程入口
 * 
 * 提供：
 * - 窗口管理
 * - IPC 处理器注册
 * - 文件系统 API
 * - SQLite 连接（待实现）
 */

import { app, BrowserWindow, ipcMain, dialog, shell, safeStorage } from 'electron'
import path from 'path'
import fs, { FSWatcher } from 'fs'
import { setupYamlHandlers } from './yamlService'

// 重新导出 main.ts 的功能
// 这是为了保持统一的导入路径：import { createWindow } from '../src/main/index'

// 保持对窗口对象的全局引用，避免被垃圾回收
let mainWindow: BrowserWindow | null = null

// 项目根目录 - 用于路径验证
let projectRootPath: string | null = null

// 文件系统监视器
let fsWatcher: FSWatcher | null = null

/**
 * 验证文件路径是否安全
 * 防止路径遍历攻击 (如 ../../../etc/passwd)
 * 只允许访问项目目录内的文件
 */
function validatePath(requestedPath: string): { valid: boolean; resolvedPath?: string; error?: string } {
  // 如果没有设置项目根路径，允许绝对路径但进行基本验证
  if (!projectRootPath) {
    // 解析并规范化路径
    const resolved = path.resolve(requestedPath)

    // 检查是否尝试访问系统敏感目录
    const sensitivePaths = [
      '/etc',
      '/proc',
      '/sys',
      'C:\\Windows',
      'C:\\Program Files',
      'C:\\Program Files (x86)',
    ]

    for (const sensitive of sensitivePaths) {
      if (resolved.toLowerCase().startsWith(sensitive.toLowerCase())) {
        return {
          valid: false,
          error: `访问被拒绝：不允许访问系统目录`,
        }
      }
    }

    return { valid: true, resolvedPath: resolved }
  }

  // 解析并规范化请求的路径
  const resolved = path.resolve(requestedPath)
  const normalizedRequested = path.normalize(resolved)
  const normalizedRoot = path.normalize(projectRootPath)

  // 确保请求的路径在项目根目录内
  if (!normalizedRequested.startsWith(normalizedRoot)) {
    return {
      valid: false,
      error: `访问被拒绝：路径必须在项目目录内 (${projectRootPath})`,
    }
  }

  return { valid: true, resolvedPath: resolved }
}

/**
 * 创建应用窗口
 */
function createWindow(): BrowserWindow {
  mainWindow = new BrowserWindow({
    width: 1400,
    height: 900,
    minWidth: 1000,
    minHeight: 700,
    title: '🍅 番茄小说创作助手',
    webPreferences: {
      preload: path.join(__dirname, '..', 'preload', 'index.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: false,
    },
    show: false,
  })

  // 窗口准备好后显示
  mainWindow.once('ready-to-show', () => {
    mainWindow?.show()
  })

  // 窗口关闭时清理
  mainWindow.on('closed', () => {
    mainWindow = null
  })

  return mainWindow
}

/**
 * 关闭应用窗口
 */
function closeWindow(): void {
  if (mainWindow) {
    mainWindow.close()
    mainWindow = null
  }
}

/**
 * 设置项目根路径
 */
function setProjectRoot(rootPath: string): void {
  projectRootPath = path.resolve(rootPath)
}

/**
 * 设置 IPC 处理器
 * 所有主进程功能通过 IPC 暴露给渲染进程
 */
function setupIpcHandlers(): void {
  // ========== 对话框 ==========
  ipcMain.handle('dialog:openDirectory', async () => {
    const result = await dialog.showOpenDialog({
      properties: ['openDirectory'],
    })

    if (!result.canceled && result.filePaths.length > 0) {
      const selectedPath = result.filePaths[0]
      setProjectRoot(selectedPath)
      return selectedPath
    }
    return undefined
  })

  // ========== 文件系统 - 读取操作 ==========
  ipcMain.handle('fs:readFile', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      const content = await fs.promises.readFile(validation.resolvedPath!, 'utf-8')
      return { success: true, content }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:exists', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return false
      }

      await fs.promises.access(validation.resolvedPath!)
      return true
    } catch {
      return false
    }
  })

  ipcMain.handle('fs:readdir', async (_event, dirPath: string) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      const entries = await fs.promises.readdir(validation.resolvedPath!, { withFileTypes: true })
      const result = entries.map(entry => ({
        name: entry.name,
        isDirectory: entry.isDirectory(),
        isFile: entry.isFile(),
      }))
      return result
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 文件系统 - 写入操作 ==========
  ipcMain.handle('fs:writeFile', async (_event, filePath: string, content: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      // 确保父目录存在
      const dir = path.dirname(validation.resolvedPath!)
      await fs.promises.mkdir(dir, { recursive: true })

      await fs.promises.writeFile(validation.resolvedPath!, content, 'utf-8')
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:mkdir', async (_event, dirPath: string) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.mkdir(validation.resolvedPath!, { recursive: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 文件系统 - 删除操作 ==========
  ipcMain.handle('fs:unlink', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.unlink(validation.resolvedPath!)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:rmdir', async (_event, dirPath: string, options?: { recursive?: boolean }) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.rm(validation.resolvedPath!, { recursive: options?.recursive, force: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:remove', async (_event, targetPath: string) => {
    try {
      const validation = validatePath(targetPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.rm(validation.resolvedPath!, { recursive: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:rename', async (_event, oldPath: string, newPath: string) => {
    try {
      const oldValidation = validatePath(oldPath)
      const newValidation = validatePath(newPath)

      if (!oldValidation.valid) {
        return { success: false, error: oldValidation.error }
      }
      if (!newValidation.valid) {
        return { success: false, error: newValidation.error }
      }

      await fs.promises.rename(oldValidation.resolvedPath!, newValidation.resolvedPath!)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 系统 ==========
  ipcMain.handle('shell:openPath', async (_event, path: string) => {
    return shell.openPath(path)
  })

  // ========== 项目 ==========
  ipcMain.handle('project:getRoot', () => {
    return projectRootPath
  })

  // ========== 文件系统监听 ==========
  ipcMain.handle('fs:watch', async (_event, dirPath?: string) => {
    try {
      // 停止之前的监视
      if (fsWatcher) {
        await fsWatcher.close()
        fsWatcher = null
      }

      const watchPath = dirPath 
        ? validatePath(dirPath).resolvedPath 
        : projectRootPath

      if (!watchPath) {
        return { success: false, error: '没有可监视的路径' }
      }

      fsWatcher = fs.watch(watchPath, { recursive: true }, (eventType, filename) => {
        if (filename && mainWindow) {
          mainWindow.webContents.send('fs:change', {
            type: eventType,
            fileName: filename,
            path: path.join(watchPath, filename),
          })
        }
      })

      return { success: true, path: watchPath }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:unwatch', async () => {
    try {
      if (fsWatcher) {
        await fsWatcher.close()
        fsWatcher = null
      }
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 安全存储 ==========
  ipcMain.handle('safeStorage:encrypt', async (_event, plainText: string) => {
    try {
      if (!safeStorage.isEncryptionAvailable()) {
        return { success: false, error: '加密不可用' }
      }
      const encrypted = safeStorage.encryptString(plainText)
      return { success: true, data: encrypted }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('safeStorage:decrypt', async (_event, encrypted: Buffer) => {
    try {
      if (!safeStorage.isEncryptionAvailable()) {
        return { success: false, error: '加密不可用' }
      }
      const decrypted = safeStorage.decryptString(encrypted)
      return { success: true, data: decrypted }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('safeStorage:isAvailable', () => {
    return { success: true, available: safeStorage.isEncryptionAvailable() }
  })

  // ========== AI 服务 ==========
  // 导入 AI 服务
  const { setupAiHandlers } = require('./aiService')
  setupAiHandlers(ipcMain)

  // ========== 备份服务 ==========
  // 导入备份服务
  const { setupBackupHandlers } = require('./backupService')
  setupBackupHandlers(ipcMain)

  // ========== YAML 服务 ==========
  setupYamlHandlers(ipcMain)
}

/**
 * 启动应用
 */
async function startApp(): Promise<void> {
  // 设置 IPC 处理器
  setupIpcHandlers()

  // 创建窗口
  createWindow()

  // 加载应用
  if (process.env.NODE_ENV === 'development') {
    await mainWindow?.loadURL('http://localhost:5173')
    mainWindow?.webContents.openDevTools()
  } else {
    await mainWindow?.loadFile(path.join(__dirname, '../renderer/index.html'))
  }
}

// 应用就绪
app.whenReady().then(startApp)

// 所有窗口关闭时退出
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow()
  }
})

// 导出供测试和主进程入口使用
export { 
  createWindow, 
  closeWindow, 
  setupIpcHandlers, 
  setProjectRoot,
  startApp,
  projectRootPath 
}

/**
 * AI 服务 - 主进程 IPC 处理器
 * 处理渲染进程发来的 AI 相关 IPC 调用
 */

import { IpcMain, BrowserWindow } from 'electron'
import axios, { AxiosError } from 'axios'
import fs from 'node:fs'
import path from 'node:path'
import os from 'node:os'
import { app } from 'electron'

// ─── 配置路径 ────────────────────────────────────────────────────────────────

function getSettingsPath(): string {
  return path.join(app.getPath('userData'), 'ai-settings.json')
}

// ─── 配置读写 ────────────────────────────────────────────────────────────────

interface AiSettings {
  deepseekApiKey?: string
  doubaoApiKey?: string
  [key: string]: string | undefined
}

function loadSettings(): AiSettings {
  const p = getSettingsPath()
  if (fs.existsSync(p)) {
    try {
      return JSON.parse(fs.readFileSync(p, 'utf-8'))
    } catch {
      return {}
    }
  }
  return {}
}

function saveSettings(settings: AiSettings): void {
  const p = getSettingsPath()
  fs.mkdirSync(path.dirname(p), { recursive: true })
  fs.writeFileSync(p, JSON.stringify(settings, null, 2), 'utf-8')
}

// ─── API 调用 ────────────────────────────────────────────────────────────────

interface CallOptions {
  model?: string
  systemPrompt?: string
  temperature?: number
  maxTokens?: number
  topP?: number
  presencePenalty?: number
  frequencyPenalty?: number
}

async function callAI(
  prompt: string,
  options: CallOptions = {}
): Promise<{ success: boolean; content?: string; reasoning?: string; error?: string }> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    return {
      success: false,
      error: `未配置 API Key。请先在设置中配置 ${model} 的 API Key。`,
    }
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    if (isDeepSeek) {
      const deepseekModel = model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat'
      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        {
          model: deepseekModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    if (model === 'doubao-pro' || model === 'doubao-lite' || model === 'doubao-mini') {
      const endpoint = model === 'doubao-pro'
        ? 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'
        : 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'

      const doubaoModel = model === 'doubao-pro'
        ? 'doubao-pro-32k'
        : model === 'doubao-lite'
          ? 'doubao-lite-32k'
          : 'doubao-mini'

      const response = await axios.post(
        endpoint,
        {
          model: doubaoModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    return { success: false, error: `不支持的模型: ${model}` }
  } catch (err) {
    const axiosErr = err as AxiosError
    if (axiosErr.response) {
      return { success: false, error: `API 错误 ${axiosErr.response.status}: ${JSON.stringify(axiosErr.response.data)}` }
    }
    return { success: false, error: `请求失败: ${axiosErr.message}` }
  }
}

async function streamAI(
  prompt: string,
  options: CallOptions,
  sendChunk: (content: string, done: boolean, reasoning?: string) => void,
  sendError: (error: string) => void
): Promise<void> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    sendError(`未配置 API Key。请先在设置中配置 ${model} 的 API Key。`)
    sendChunk('', true)
    return
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    }

    const body: Record<string, unknown> = {
      model: isDeepSeek
        ? (model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat')
        : 'doubao-pro-32k',
      messages: [
        ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
        { role: 'user', content: prompt },
      ],
      temperature,
      max_tokens: maxTokens,
    }

    // DeepSeek（实际也是火山引擎 Doubao 端）支持流式
    if (isDeepSeek) {
      body.stream = true

      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        body,
        {
          headers,
          responseType: 'stream',
          timeout: 120000,
        }
      )

      const stream = response.data as import('node:stream').Stream
      let buffer = ''

      await new Promise<void>((resolve, reject) => {
        stream.on('data', (chunk: Buffer) => {
          buffer += chunk.toString()
          const lines = buffer.split('\n')
          buffer = lines.pop() || ''

          for (const line of lines) {
            const trimmed = line.trim()
            if (!trimmed || trimmed === 'data: [DONE]') continue
            if (!trimmed.startsWith('data: ')) continue
            const data = trimmed.slice(6)
            try {
              const parsed = JSON.parse(data)
              const content = parsed.choices?.[0]?.delta?.content || ''
              const reasoning = parsed.choices?.[0]?.delta?.reasoning || ''
              if (content || reasoning) {
                sendChunk(content, false, reasoning)
              }
            } catch {}
          }
        })

        stream.on('end', () => {
          if (buffer.trim() && buffer.trim() !== '[DONE]') {
            try {
              const data = JSON.parse(buffer.slice(6))
              const content = data.choices?.[0]?.delta?.content || ''
              if (content) sendChunk(content, false)
            } catch {}
          }
          sendChunk('', true)
          resolve()
        })

        stream.on('error', (err: Error) => {
          sendError(err.message)
          sendChunk('', true)
          resolve()
        })
      })
    } else {
      // 非流式降级
      const result = await callAI(prompt, options)
      if (result.success) {
        sendChunk(result.content || '', false)
        sendChunk('', true)
      } else {
        sendError(result.error || '未知错误')
        sendChunk('', true)
      }
    }
  } catch (err) {
    const axiosErr = err as AxiosError
    sendError(axiosErr.message || '请求失败')
    sendChunk('', true)
  }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupAiHandlers(ipcMain: IpcMain): void {
  // 保存 API Key
  ipcMain.handle('ai:saveApiKey', async (_event, service: string, apiKey: string) => {
    try {
      const settings = loadSettings()
      settings[`${service}ApiKey`] = apiKey
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 检查是否已配置
  ipcMain.handle('ai:isConfigured', async (_event, service: string) => {
    const settings = loadSettings()
    const configured = !!(settings[`${service}ApiKey`] || process.env[`${service.toUpperCase()}_API_KEY`])
    return { success: true, configured }
  })

  // 获取已配置的服务列表
  ipcMain.handle('ai:getConfiguredServices', async () => {
    const settings = loadSettings()
    const services: string[] = []
    if (settings.deepseekApiKey || process.env.DEEPSEEK_API_KEY) services.push('deepseek')
    if (settings.doubaoApiKey || process.env.DOUBAO_API_KEY) services.push('doubao')
    return { success: true, services }
  })

  // AI 调用（非流式）
  ipcMain.handle('ai:call', async (_event, prompt: string, options?: CallOptions) => {
    return callAI(prompt, options || {})
  })

  // AI 流式调用
  ipcMain.handle('ai:stream', async (event, prompt: string, options?: CallOptions) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (!win || win.isDestroyed()) return { success: false, error: '窗口已关闭' }

    await streamAI(
      prompt,
      options || {},
      (content, done, reasoning) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-chunk', { content, done, reasoning })
        }
      },
      (error) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-error', error)
        }
      }
    )

    return { success: true }
  })

  // 测试连接
  ipcMain.handle('ai:testConnection', async (_event, service: string) => {
    const testPrompt = '请回复"连接成功"，不需要其他内容。'
    const result = await callAI(testPrompt, { model: service, maxTokens: 50 })
    return { success: result.success, result: result.success, error: result.error }
  })

  // 保存设置
  ipcMain.handle('ai:saveSetting', async (_event, key: string, value: any) => {
    try {
      const settings = loadSettings()
      settings[key] = value
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 读取设置
  ipcMain.handle('ai:getSetting', async (_event, key: string, defaultValue?: any) => {
    const settings = loadSettings()
    return { success: true, value: settings[key] ?? defaultValue }
  })
}

/**
 * 备份服务 - 主进程 IPC 处理器
 * 处理小说项目的备份/恢复
 */

import { IpcMain, app } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import zlib from 'node:zlib'
import { promisify } from 'node:util'

const gzip = promisify(zlib.gzip)
const gunzip = promisify(zlib.gunzip)

const BACKUP_DIR = path.join(app.getPath('userData'), 'backups')
const BACKUP_INDEX = path.join(BACKUP_DIR, 'index.json')

interface BackupEntry {
  name: string
  path: string
  date: string
  size: number
  description?: string
}

function loadIndex(): BackupEntry[] {
  if (!fs.existsSync(BACKUP_INDEX)) return []
  try {
    return JSON.parse(fs.readFileSync(BACKUP_INDEX, 'utf-8'))
  } catch {
    return []
  }
}

function saveIndex(index: BackupEntry[]): void {
  fs.mkdirSync(BACKUP_DIR, { recursive: true })
  fs.writeFileSync(BACKUP_INDEX, JSON.stringify(index, null, 2), 'utf-8')
}

// 递归压缩目录为一个 gzip 文件
async function compressDir(dirPath: string, relativeRoot: string): Promise<Buffer> {
  const entries: { path: string; relativePath: string; isDir: boolean }[] = []

  function walk(dir: string): void {
    const items = fs.readdirSync(dir)
    for (const item of items) {
      const full = path.join(dir, item)
      const rel = path.relative(relativeRoot, full)
      const stat = fs.statSync(full)
      if (stat.isDirectory()) {
        entries.push({ path: full, relativePath: rel + '/', isDir: true })
        walk(full)
      } else {
        entries.push({ path: full, relativePath: rel, isDir: false })
      }
    }
  }
  walk(dirPath)

  // 构建文件列表 JSON
  const manifest = JSON.stringify(entries, null, 2)
  const manifestBuf = Buffer.from(manifest, 'utf-8')

  const parts: Buffer[] = []
  // 格式：4字节manifest长度 + manifest JSON + 各文件内容
  const manifestLenBuf = Buffer.alloc(4)
  manifestLenBuf.writeUInt32BE(manifestBuf.length, 0)
  parts.push(manifestLenBuf, manifestBuf)

  for (const entry of entries) {
    if (entry.isDir) continue
    const content = fs.readFileSync(entry.path)
    const nameBuf = Buffer.from(entry.relativePath, 'utf-8')
    const nameLenBuf = Buffer.alloc(2)
    nameLenBuf.writeUInt16BE(nameBuf.length, 0)
    const sizeBuf = Buffer.alloc(4)
    sizeBuf.writeUInt32BE(content.length, 0)
    parts.push(nameLenBuf, nameBuf, sizeBuf, content)
  }

  const combined = Buffer.concat(parts)
  return gzip(combined)
}

async function decompressBackup(
  archivePath: string,
  targetDir: string
): Promise<void> {
  const raw = fs.readFileSync(archivePath)
  const decompressed = await gunzip(raw)

  let offset = 0

  // 读取 manifest
  const manifestLen = decompressed.readUInt32BE(offset)
  offset += 4
  const manifest = JSON.parse(decompressed.slice(offset, offset + manifestLen).toString('utf-8'))
  offset += manifestLen

  // 清空目标目录
  if (fs.existsSync(targetDir)) {
    fs.rmSync(targetDir, { recursive: true })
  }
  fs.mkdirSync(targetDir, { recursive: true })

  // 恢复每个文件
  for (const entry of manifest) {
    if (entry.isDir) {
      fs.mkdirSync(path.join(targetDir, entry.relativePath), { recursive: true })
      continue
    }

    const nameLen = decompressed.readUInt16BE(offset)
    offset += 2
    // skip name (already have from manifest)
    offset += nameLen
    const size = decompressed.readUInt32BE(offset)
    offset += 4
    const content = decompressed.slice(offset, offset + size)
    offset += size

    const fullPath = path.join(targetDir, entry.relativePath)
    fs.mkdirSync(path.dirname(fullPath), { recursive: true })
    fs.writeFileSync(fullPath, content)
  }
}

function getBackupSize(archivePath: string): number {
  try {
    return fs.statSync(archivePath).size
  } catch {
    return 0
  }
}

export function setupBackupHandlers(ipcMain: IpcMain): void {
  // 创建备份
  ipcMain.handle('backup:create', async (_event, projectPath?: string) => {
    try {
      if (!projectPath) {
        return { success: false, error: '未提供项目路径' }
      }
      if (!fs.existsSync(projectPath)) {
        return { success: false, error: '项目路径不存在' }
      }

      fs.mkdirSync(BACKUP_DIR, { recursive: true })

      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19)
      const name = path.basename(projectPath) + '_' + timestamp
      const archivePath = path.join(BACKUP_DIR, name + '.nbackup')

      const archive = await compressDir(projectPath, projectPath)
      fs.writeFileSync(archivePath, archive)

      const entry: BackupEntry = {
        name,
        path: archivePath,
        date: new Date().toISOString(),
        size: archive.length,
      }

      const index = loadIndex()
      index.unshift(entry)
      saveIndex(index)

      return { success: true, backupPath: archivePath }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 列出备份
  ipcMain.handle('backup:list', async () => {
    try {
      const index = loadIndex()
      // 清理不存在的备份记录
      const valid = index.filter(e => fs.existsSync(e.path))
      if (valid.length !== index.length) {
        saveIndex(valid)
      }
      return {
        success: true,
        backups: valid.map(e => ({
          name: e.name,
          path: e.path,
          date: e.date,
          size: e.size,
        })),
      }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 恢复备份
  ipcMain.handle('backup:restore', async (_event, backupPath: string, targetPath?: string) => {
    try {
      if (!fs.existsSync(backupPath)) {
        return { success: false, error: '备份文件不存在' }
      }
      if (!targetPath) {
        return { success: false, error: '未提供恢复目标路径' }
      }
      // 验证目标路径安全（防止路径遍历）
      const resolved = path.resolve(targetPath)
      if (resolved.startsWith('/etc') || resolved.match(/^[A-Z]:\\(Windows|Program Files)/i)) {
        return { success: false, error: '禁止恢复到系统路径' }
      }

      await decompressBackup(backupPath, targetPath)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 删除备份
  ipcMain.handle('backup:delete', async (_event, backupPath: string) => {
    try {
      if (fs.existsSync(backupPath)) {
        fs.unlinkSync(backupPath)
      }
      const index = loadIndex()
      saveIndex(index.filter(e => e.path !== backupPath))
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })
}

/**
 * YAML 服务 - 主进程 IPC 处理器
 * 提供 YAML 文件的安全读写，解析和序列化
 * 所有路径操作必须经过 validatePath 验证，防止目录遍历攻击
 */

import { IpcMain } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import yaml from 'js-yaml'

// ─── 路径验证（与 index.ts 保持一致） ───────────────────────────────────────

function validateYamlPath(requestedPath: string): { valid: boolean; resolvedPath?: string; error?: string } {
  // yamlService 只允许操作项目子目录下的 facts/ 目录
  //  Facts 目录固定在 {projectRoot}/facts/
  // 但由于 yamlService 不持有 projectRoot，需要由调用方（factsStore）保证传入合法路径
  // 这里做最后一道防线：禁止跨盘符访问和敏感路径
  const normalized = path.normalize(path.resolve(requestedPath))

  const sensitivePaths = [
    'C:\\Windows',
    'C:\\Program Files',
    '/etc',
    '/usr',
    '/root',
    '/home',
  ]

  for (const sensitive of sensitivePaths) {
    if (normalized.toLowerCase().startsWith(sensitive.toLowerCase())) {
      return { valid: false, error: `禁止访问系统路径: ${sensitive}` }
    }
  }

  return { valid: true, resolvedPath: normalized }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupYamlHandlers(ipcMain: IpcMain): void {
  ipcMain.handle('yaml:read', async (_event, filePath: string): Promise<{ success: boolean; data?: any; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      if (!fs.existsSync(validation.resolvedPath!)) {
        return { success: false, error: '文件不存在' }
      }
      const content = fs.readFileSync(validation.resolvedPath!, 'utf-8')
      const data = yaml.load(content)
      return { success: true, data }
    } catch (e: any) {
      return { success: false, error: `YAML 解析失败: ${e.message}` }
    }
  })

  ipcMain.handle('yaml:write', async (_event, filePath: string, data: any): Promise<{ success: boolean; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      const dir = path.dirname(validation.resolvedPath!)
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true })
      }
      const yamlStr = yaml.dump(data)
      fs.writeFileSync(validation.resolvedPath!, yamlStr, 'utf-8')
      return { success: true }
    } catch (e: any) {
      return { success: false, error: `YAML 写入失败: ${e.message}` }
    }
  })
}

/**
 * 番茄小说创作助手 - 预加载脚本入口
 * 
 * 暴露安全的 API 给渲染进程
 * 所有 API 通过 contextBridge 暴露
 */

import { contextBridge, ipcRenderer } from 'electron'

// 重新导出 preload.ts 的功能
// 保持统一的导入路径

/**
 * 暴露安全的 API 给渲染进程
 */
function exposeElectronAPI(): void {
  contextBridge.exposeInMainWorld('electronAPI', {
    // 对话框
    openDirectory: () => ipcRenderer.invoke('dialog:openDirectory'),

    // 文件系统 - 读取操作
    readFile: (filePath: string) => ipcRenderer.invoke('fs:readFile', filePath),
    exists: (filePath: string) => ipcRenderer.invoke('fs:exists', filePath),
    readdir: (dirPath: string) => ipcRenderer.invoke('fs:readdir', dirPath),

    // 文件系统 - 写入操作
    writeFile: (filePath: string, content: string) => 
      ipcRenderer.invoke('fs:writeFile', filePath, content),
    mkdir: (dirPath: string) => ipcRenderer.invoke('fs:mkdir', dirPath),

    // 文件系统 - 删除操作
    unlink: (filePath: string) => ipcRenderer.invoke('fs:unlink', filePath),
    rmdir: (dirPath: string, options?: { recursive?: boolean }) => 
      ipcRenderer.invoke('fs:rmdir', dirPath, options),
    remove: (targetPath: string) => ipcRenderer.invoke('fs:remove', targetPath),

    // 便捷删除方法
    deleteFile: (filePath: string) => ipcRenderer.invoke('fs:unlink', filePath),
    deleteDirectory: (dirPath: string) => ipcRenderer.invoke('fs:rmdir', dirPath, { recursive: true }),
    renameFile: (oldPath: string, newPath: string) => ipcRenderer.invoke('fs:rename', oldPath, newPath),

    // 系统
    openPath: (path: string) => ipcRenderer.invoke('shell:openPath', path),

    // 项目
    getProjectRoot: () => ipcRenderer.invoke('project:getRoot'),

    // 文件系统监听
    fsWatch: (dirPath?: string) => ipcRenderer.invoke('fs:watch', dirPath),
    fsUnwatch: () => ipcRenderer.invoke('fs:unwatch'),
    onFsChange: (callback: (data: { type: string; fileName: string; path: string }) => void) => {
      const handler = (_event: any, data: any) => callback(data)
      ipcRenderer.on('fs:change', handler)
      return () => ipcRenderer.removeListener('fs:change', handler)
    },

    // 安全存储 - 用于加密存储 API Key 等敏感信息
    safeStorage: {
      encrypt: (plainText: string) => ipcRenderer.invoke('safeStorage:encrypt', plainText),
      decrypt: (encrypted: Buffer) => ipcRenderer.invoke('safeStorage:decrypt', encrypted),
      isAvailable: () => ipcRenderer.invoke('safeStorage:isAvailable'),
    },

    // ==================== YAML 服务 API ====================
    yaml: {
      read: (filePath: string) => ipcRenderer.invoke('yaml:read', filePath),
      write: (filePath: string, data: any) => ipcRenderer.invoke('yaml:write', filePath, data),
    },

    // ==================== AI 服务 API ====================

    // AI Key 管理
    ai: {
      saveApiKey: (service: string, apiKey: string) => 
        ipcRenderer.invoke('ai:saveApiKey', service, apiKey),

      isConfigured: (service: string) => 
        ipcRenderer.invoke('ai:isConfigured', service),

      getConfiguredServices: () => 
        ipcRenderer.invoke('ai:getConfiguredServices'),

      call: (prompt: string, options?: any) => 
        ipcRenderer.invoke('ai:call', prompt, options),

      stream: (prompt: string, options?: any) => 
        ipcRenderer.invoke('ai:stream', prompt, options),

      onStreamChunk: (callback: (chunk: { content: string; done: boolean; reasoning?: string }) => void) => {
        const handler = (_event: any, chunk: any) => callback(chunk as { content: string; done: boolean; reasoning?: string })
        ipcRenderer.on('ai:stream-chunk', handler)
        return () => ipcRenderer.removeListener('ai:stream-chunk', handler)
      },

      onStreamError: (callback: (error: string) => void) => {
        const handler = (_event: any, error: any) => callback(error as string)
        ipcRenderer.on('ai:stream-error', handler)
        return () => ipcRenderer.removeListener('ai:stream-error', handler)
      },

      testConnection: (service: string) => 
        ipcRenderer.invoke('ai:testConnection', service),

      saveSetting: (key: string, value: any) => 
        ipcRenderer.invoke('ai:saveSetting', key, value),

      getSetting: (key: string, defaultValue?: any) => 
        ipcRenderer.invoke('ai:getSetting', key, defaultValue),
    },

    // ==================== 备份服务 API ====================

    backup: {
      create: () => ipcRenderer.invoke('backup:create'),
      list: () => ipcRenderer.invoke('backup:list'),
      restore: (backupPath: string) => ipcRenderer.invoke('backup:restore', backupPath),
      delete: (backupPath: string) => ipcRenderer.invoke('backup:delete', backupPath),
    },
  })
}

/**
 * 初始化预加载 API
 */
